        {"verse_id": "bg-17-20", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 17, "chapter_name": "Sraddhatraya Vibhaga Yoga", "verse_number": 20, "text": "datavyam iti yad danam diyate 'nupakarine dese kale ca patre ca tad danam sattvikam smrtam", "translation": "Charity given out of duty, without expectation of return, at the proper time and place, and to a worthy person is considered to be in the mode of goodness.", "keywords": "charity, duty, goodness, sattva, giving"},

        # Chapter 18: Moksha Sanyasa Yoga
        {"verse_id": "bg-18-20", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 18, "chapter_name": "Moksha Sanyasa Yoga", "verse_number": 20, "text": "sarva-bhutesu yenaikam bhavam avyayam iksate avibhaktam vibhaktesu taj jnanam viddhi sattvikam", "translation": "That knowledge by which one undivided spiritual nature is seen in all living entities, though they are divided into innumerable forms, you should understand to be in the mode of goodness.", "keywords": "knowledge, unity, spiritual, goodness, oneness"},
        {"verse_id": "bg-18-46", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 18, "chapter_name": "Moksha Sanyasa Yoga", "verse_number": 46, "text": "yatah pravrttir bhutanam yena sarvam idam tatam sva-karmana tam abhyarcya siddhim vindati manavah", "translation": "By worship of the Lord, who is the source of all beings and who is all-pervading, a man can attain perfection through performing his own work.", "keywords": "worship, perfection, duty, devotion, work"},
        {"verse_id": "bg-18-65", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 18, "chapter_name": "Moksha Sanyasa Yoga", "verse_number": 65, "text": "man-mana bhava mad-bhakto mad-yaji mam namaskuru mam evaishyasi satyam te pratijane priyo 'si me", "translation": "Always think of Me, become My devotee, worship Me and offer your homage unto Me. Thus you will come to Me without fail. I promise you this because you are My very dear friend.", "keywords": "devotion, worship, promise, friendship, surrender, love"},
        {"verse_id": "bg-18-66", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 18, "chapter_name": "Moksha Sanyasa Yoga", "verse_number": 66, "text": "sarva-dharman parityajya mam ekam saranam vraja aham tvam sarva-papebhyo moksayisyami ma sucah", "translation": "Abandon all varieties of religion and just surrender unto Me. I shall deliver you from all sinful reactions. Do not fear.", "keywords": "surrender, liberation, moksha, fearlessness, divine grace, salvation"},
        {"verse_id": "bg-18-78", "text_id": "bhagavad-gita", "text_name": "Bhagavad Gita", "chapter": 18, "chapter_name": "Moksha Sanyasa Yoga", "verse_number": 78, "text": "yatra yogesvarah krsno yatra partho dhanur-dharah tatra srir vijayo bhutir dhruva nitir matir mama", "translation": "Wherever there is Krishna, the master of all mystics, and wherever there is Arjuna, the supreme archer, there will also certainly be opulence, victory, extraordinary power, and morality.", "keywords": "Krishna, Arjuna, victory, opulence, morality, conclusion"},
