        {"verse_id": "ram-1-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 1, "chapter_name": "Bala Kanda", "verse_number": 2, "text": "ko nv asmin saampratam loke gunavaan kash ca viiryavaan dharmajna ca krtajna ca satya vaakyo drdha vratah", "translation": "Who in this world today is virtuous, heroic, dutiful, grateful, truthful, and firm in his vows?", "keywords": "virtue, hero, duty, truth, qualities, ideal man"},
        {"verse_id": "ram-1-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 1, "chapter_name": "Bala Kanda", "verse_number": 3, "text": "ikshvaaku vamsha prabhavo raamo naama janai shrutah niyataatmaa mahaa viiryah dyutimaan dhrtimaan vashii", "translation": "Born in the Ikshvaku dynasty, known as Rama, he is self-controlled, mighty, radiant, resolute, and master of his senses.", "keywords": "Rama, Ikshvaku, self-control, mighty, radiant"},
        {"verse_id": "ram-1-4", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 1, "chapter_name": "Bala Kanda", "verse_number": 4, "text": "sa ca sarvagunopetah kausalyaa nanda vardhanah samudra iva gaambhiirye dhairyeNa himavaan iva", "translation": "Endowed with all virtues, the joy of Kausalya, he is deep as the ocean in gravity and firm as the Himalayas in courage.", "keywords": "Rama, virtues, ocean, Himalayas, courage, Kausalya"},
        {"verse_id": "ram-1-5", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 1, "chapter_name": "Bala Kanda", "verse_number": 5, "text": "maa nishada pratisthaam tvam agamah shaashvatii samah yat krauncha mithunaat ekam avadhih kaama mohitam", "translation": "O hunter! May you not achieve rest for eternity, for you killed one of a pair of cranes, absorbed in love.", "keywords": "first verse, poetry, compassion, hunter, crane, Valmiki, origin of poetry"},

        # Ayodhya Kanda (Book of Ayodhya)
        {"verse_id": "ram-2-1", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 2, "chapter_name": "Ayodhya Kanda", "verse_number": 1, "text": "pitur vacanam atigamya raamo daasharathih svayam pratasthe vanavaasamya siitaa lakshmanasahitah", "translation": "Honoring his father's word, Rama, the son of Dasharatha, set out for the forest exile, accompanied by Sita and Lakshmana.", "keywords": "exile, forest, duty, father, Rama, Sita, Lakshmana, Dasharatha"},
        {"verse_id": "ram-2-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 2, "chapter_name": "Ayodhya Kanda", "verse_number": 2, "text": "raamo vigrahavaan dharmah saadhu satyaparaaKramah raajaa sarvasya lokasya devaanam iva vaasavah", "translation": "Rama is the embodiment of Dharma, noble and of truthful valor. He is the king of the whole world, as Indra is to the gods.", "keywords": "Rama, dharma, embodiment, righteousness, king, truth"},
        {"verse_id": "ram-2-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 2, "chapter_name": "Ayodhya Kanda", "verse_number": 3, "text": "na dainya na ca maatsaryam na lobho na shubhaa matih na ca api dainya bhavo vaa drsyate raama sevine", "translation": "Neither sorrow, nor jealousy, nor greed, nor impure thought, nor any meanness is found in one who serves Rama.", "keywords": "service, devotion, purity, Rama, jealousy, greed"},
        {"verse_id": "ram-2-4", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 2, "chapter_name": "Ayodhya Kanda", "verse_number": 4, "text": "atma svaartham parityajya yo anyesham hitam icchhati sarvam tasmai prayacchanti na ca taih paryudasyate", "translation": "He who sacrifices self-interest and desires the welfare of others - to him the world gives everything, and he is never forsaken.", "keywords": "selflessness, welfare, sacrifice, giving, compassion"},

        # Aranya Kanda (Book of the Forest)
        {"verse_id": "ram-3-1", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 3, "chapter_name": "Aranya Kanda", "verse_number": 1, "text": "dharmo rakshati rakshitah", "translation": "Dharma protects those who protect dharma.", "keywords": "dharma, protection, righteousness, universal law"},
        {"verse_id": "ram-3-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 3, "chapter_name": "Aranya Kanda", "verse_number": 2, "text": "aatmaanam manushah raama paapaat rakshatu satatam vane vaa raaja veShme vaa apsu vaa sharaNe api vaa", "translation": "O Rama, a man should constantly protect himself from sin, whether in the forest, the palace, in water, or in any refuge.", "keywords": "sin, protection, self-discipline, forest, Rama"},
        {"verse_id": "ram-3-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 3, "chapter_name": "Aranya Kanda", "verse_number": 3, "text": "siitaa apaharaNam caiva jaataayoh ca vadhah tathaa raavaNasya ca darpaghnam vaanareNa sahaayatah", "translation": "The abduction of Sita, the slaying of Jatayu, and the humbling of Ravana's pride with the help of the Vanaras.", "keywords": "Sita, abduction, Jatayu, Ravana, Vanaras"},

        # Kishkindha Kanda (Book of Kishkindha)
        {"verse_id": "ram-4-1", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 4, "chapter_name": "Kishkindha Kanda", "verse_number": 1, "text": "vaali vinihato raameNa sugriivasya hitam karan sugriivo raama sahitah siitaam maargiShyate puraat", "translation": "Vali was slain by Rama for the benefit of Sugriva. Sugriva, allied with Rama, shall search for Sita.", "keywords": "Vali, Sugriva, alliance, Sita, search, friendship"},
        {"verse_id": "ram-4-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 4, "chapter_name": "Kishkindha Kanda", "verse_number": 2, "text": "snigdhena dhiiraa vipulena cakShushaa raamo mayaa paarthiva putra iiksitah shuShyat mukhena parishoshitaa dharah tena iiva samvatshar gaNo ativartate", "translation": "With moist, deep, and wide eyes, Rama, the prince, was gazed upon by me. With a withered face and parched lips, thus passed a year for him.", "keywords": "Rama, separation, grief, Sita, yearning, prince"},

