        {"verse_id": "ram-5-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 5, "chapter_name": "Sundara Kanda", "verse_number": 2, "text": "buddhir balamyadhiShThaanaM dharmo vidyaa ca panchami etaani yasya vartante tasya devah sahaayakrt", "translation": "Intelligence, strength, a good foundation, righteousness, and knowledge as the fifth - to whom these five belong, the gods become his helpers.", "keywords": "intelligence, strength, dharma, knowledge, divine help"},
        {"verse_id": "ram-5-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 5, "chapter_name": "Sundara Kanda", "verse_number": 3, "text": "na hi praaNaparikShepe mama raameNa samgamah sukhaM caa aham rameta iha paraH ca aapi mama shashvatam", "translation": "If I give up my life, I shall never meet Rama again. Let me endure here, for my patience is eternal.", "keywords": "Sita, endurance, patience, hope, Rama, Lanka"},
        {"verse_id": "ram-5-4", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 5, "chapter_name": "Sundara Kanda", "verse_number": 4, "text": "nahi me jeevitena artho na arthairna ca sukhena vaa raamamarthaH anaagatya yaa jeevami vipulaamshucham", "translation": "I have no use for life, wealth, or happiness while Rama has not come. That I live bearing such immense sorrow is itself a wonder.", "keywords": "Sita, sorrow, love, devotion, Rama, Lanka, longing"},

        # Yuddha Kanda (Book of War)
        {"verse_id": "ram-6-1", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 6, "chapter_name": "Yuddha Kanda", "verse_number": 1, "text": "nahi praapnoti dharmaaatmaa saadhu vinasha maashritah apradushTa svabhaavo hi na dushTim gaantumarhati", "translation": "A righteous soul devoted to good can never be destroyed. One whose nature is pure cannot be tainted.", "keywords": "righteousness, purity, soul, protection, dharma"},
        {"verse_id": "ram-6-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 6, "chapter_name": "Yuddha Kanda", "verse_number": 2, "text": "api svarNamayii lankaa na me lakShmaNa rochate jananii janma bhuumish ca svargaadapi gariyasii", "translation": "Even this golden Lanka does not appeal to me, O Lakshmana. One's mother and motherland are greater than heaven itself.", "keywords": "motherland, patriotism, Lanka, gold, heaven, Rama, Lakshmana"},
        {"verse_id": "ram-6-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 6, "chapter_name": "Yuddha Kanda", "verse_number": 3, "text": "vijayeta suparvaano devendra sama vikramah raavaNo naama durvritto rakshasaam iishvarah prabhuh", "translation": "Let Ravana, the wicked lord of Rakshasas, whose valor equals that of Indra himself, be conquered by the noble ones.", "keywords": "Ravana, conquest, battle, valor, Indra, Lanka"},
        {"verse_id": "ram-6-4", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 6, "chapter_name": "Yuddha Kanda", "verse_number": 4, "text": "aaditya hrdayam puNyam sarva shatru vinaashanam jayaavaham japennityam akshayyam paramam shivam", "translation": "This sacred Aditya Hridayam hymn destroys all enemies, bestows victory, and brings eternal blessing and supreme auspiciousness.", "keywords": "Aditya Hridaya, sun, prayer, victory, blessing, enemies"},

        # Uttara Kanda (Book of the Aftermath)
        {"verse_id": "ram-7-1", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 7, "chapter_name": "Uttara Kanda", "verse_number": 1, "text": "raamo raajamaNih sadaa vijayate raamam ramesham bhaje raameNaabhi hataa nishaacharachamuu raamaaya tasmai namah", "translation": "Rama, the jewel among kings, always triumphs. I worship Rama, the Lord of Lakshmi. The demon army was destroyed by Rama. Salutations to that Rama.", "keywords": "Rama, victory, worship, king, salutations, triumph"},
        {"verse_id": "ram-7-2", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 7, "chapter_name": "Uttara Kanda", "verse_number": 2, "text": "raamaaya raamabhadraaya raamacandraaya vedhase raghunaathaaya naathaaya siitaayaah pataye namah", "translation": "Salutations to Rama, to the auspicious Rama, to Ramachandra the creator, to the Lord of the Raghus, to the protector, and to the husband of Sita.", "keywords": "Rama, salutation, Sita, prayer, Raghu dynasty, blessings"},
        {"verse_id": "ram-7-3", "text_id": "ramayana", "text_name": "Ramayana", "chapter": 7, "chapter_name": "Uttara Kanda", "verse_number": 3, "text": "yah patheta raama charitam sarva paapaiH pramucyate", "translation": "Whoever reads the story of Rama is freed from all sins.", "keywords": "reading, Ramayana, sin, liberation, merit, devotion"},
