        {"verse_id": "dm-2-2", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 2, "chapter_name": "Mahishasura Sainya Vadha", "verse_number": 2, "text": "tatah kopam cakaaroccaiH amaraa nihataashrayaah tasya devaaH samavetraah sharaNam prapidam hareh", "translation": "Then the devas, defeated and deprived of their abodes, became enraged and sought refuge with Lord Vishnu.", "keywords": "devas, defeat, refuge, Vishnu, anger, Mahishasura"},
        {"verse_id": "dm-2-3", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 2, "chapter_name": "Mahishasura Sainya Vadha", "verse_number": 3, "text": "tatah samastha devaanam tejaH samarabhavataha ekasthaam tadanuh kaantim bibhratim atulaam striyam", "translation": "Then from the combined radiance of all the gods emerged a woman of unparalleled brilliance, whose light filled all directions.", "keywords": "Durga, radiance, gods, creation, goddess, divine feminine, brilliance"},

        # Chapter 3: Mahishasura Vadha
        {"verse_id": "dm-3-1", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 3, "chapter_name": "Mahishasura Vadha", "verse_number": 1, "text": "tasya sinhanaadam shrutvaa devii kopena chaavritaa taamaahaviitarShaa devii gambhiira aattahaasata", "translation": "Hearing the lion's roar of that demon, the Goddess, filled with wrath and with a deep, thunderous laugh, spoke.", "keywords": "Devi, wrath, lion, laughter, Mahishasura, battle"},
        {"verse_id": "dm-3-2", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 3, "chapter_name": "Mahishasura Vadha", "verse_number": 2, "text": "tishtha tishtha duraatman mayi yudhyasva sthiro bhava devii uvaacha durga mahishaM tadaagham asuraadhipam", "translation": "Stay! Stay! O wicked one, fight me and stand firm! Thus spoke the Goddess Durga to Mahisha, the king of demons.", "keywords": "Durga, Mahisha, battle, command, bravery, goddess warrior"},
        {"verse_id": "dm-3-3", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 3, "chapter_name": "Mahishasura Vadha", "verse_number": 3, "text": "saa kshiptena cha shakreNa paashenaadbadha mahisham tyaktvaa mahishroopam so'pi svaam roopam aasthitah", "translation": "Bound by the noose of the Goddess, Mahisha abandoned his buffalo form and assumed his true form.", "keywords": "Mahisha, buffalo, transformation, bound, goddess, battle"},

