        {"verse_id": "dm-4-2", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 4, "chapter_name": "Shakra Stuti", "verse_number": 2, "text": "yaa devii sarvabhuuteshu shakti ruupena samsthitaa namastasyai namastasyai namastasyai namo namah", "translation": "To that Goddess who abides in all beings in the form of power (Shakti) - salutations to Her, salutations to Her, salutations to Her, again and again.", "keywords": "Shakti, goddess, power, salutations, all beings, divine feminine"},
        {"verse_id": "dm-4-3", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 4, "chapter_name": "Shakra Stuti", "verse_number": 3, "text": "yaa devii sarvabhuuteshu buddhi ruupena samsthitaa namastasyai namastasyai namastasyai namo namah", "translation": "To that Goddess who abides in all beings in the form of intelligence (Buddhi) - salutations to Her, salutations to Her, salutations to Her, again and again.", "keywords": "Buddhi, intelligence, goddess, salutations, all beings, wisdom"},
        {"verse_id": "dm-4-4", "text_id": "devi-mahatmyam", "text_name": "Devi Mahatmyam", "chapter": 4, "chapter_name": "Shakra Stuti", "verse_number": 4, "text": "yaa devii sarvabhuuteshu nidraa ruupena samsthitaa namastasyai namastasyai namastasyai namo namah", "translation": "To that Goddess who abides in all beings in the form of sleep (Nidra) - salutations to Her, salutations to Her, salutations to Her, again and again.", "keywords": "Nidra, sleep, goddess, salutations, all beings, rest"},
